            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
            pBias += vl;
            pContri_buf += vl;
            out_tensor_ch2--;
        }
    }
    else
    {
        long out_tensor_ch2 = out_tensor_ch;
        long vl;
        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

        while (out_tensor_ch2 > 0)
        {
            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

            long rhs_cols2 = col;
            while (rhs_cols2 >= maxvl_per_loop)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
                pWt += vl;
                rhs_cols2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
            }

            //clean one of the dot product source
            long tmp_avl;
            tmp_avl = rhs_cols2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

            // remain loop
            while (rhs_cols2 > 0)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
                pWt += vl;
                rhs_cols2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
            }

            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
            pContri_buf++;
            out_tensor_ch2--;
        }
    }

    //transpose the kernel_weight for matrix multiplication
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch * ker_dim_x * ker_dim_y);

    int8_t *out = out_tensor;
    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        int8_t *src1_buf = src1;
        int col_counter = 0;

        /* This part implements the im256col function */
        for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
        {
            for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
            {
                for (long cur_ker_y = cur_out_y * stride_y - pad_y; cur_ker_y < cur_out_y * stride_y - pad_y + ker_dim_y; cur_ker_y++)
                {
                    for (long cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + ker_dim_x; cur_ker_x++)
                    {
                        if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
                        {
                            nn_set_val_s8(src1_buf, -in_offset, in_tensor_ch);
                        }
                        else
                        {
                            nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, src1_buf, in_tensor_ch);
                        }
                        src1_buf += in_tensor_ch;
                    }
