                                                                 out_shift,
                                                                 col_counter,
                                                                 in_tensor_ch * ker_dim_x * ker_dim_y,
                                                                 out_tensor_ch,
                                                                 out_offset,
                                                                 act_min,
                                                                 act_max,
                                                                 contri_buf,
                                                                 tiling_size);

                    /* counter reset */
                    col_counter = 0;
                    src1_buf = src1;
                }
            }
        }

        /* check if there is left-over for compute */
        out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
                                                     src2,
                                                     dst_i32,
                                                     out,
